SELECT c.content_id AS content_id, c.title AS title, c.main_image_path AS main_image_path, c.location AS location, c.start_at AS start_at, c.end_at AS end_at FROM content c WHERE
AND c.end_at >= NOW()
AND c.content_kind=#{content_kind}
ORDER BY RAND() LIMIT #{limit}

SELECT * FROM ( SELECT c.*, (
CASE WHEN (
c.content_kind LIKE CONCAT('%', #{t}, '%')
) THEN 3 ELSE 0 END
0
+
CASE WHEN (
c.location LIKE CONCAT('%', #{t}, '%')
) THEN 4 ELSE 0 END
0
+
CASE WHEN (
c.category LIKE CONCAT('%', #{t}, '%')
) THEN 3 ELSE 0 END
0
) AS weight_score FROM content c
AND c.end_at >= NOW()
) t
ORDER BY t.weight_score DESC, t.start_at DESC LIMIT #{limit}

SELECT c.content_id AS content_id, c.title AS title, c.main_image_path AS main_image_path, c.category AS category, c.location AS location, c.start_at AS start_at, c.end_at AS end_at FROM content c LEFT JOIN ( SELECT content_id, COUNT(*) AS res_cnt FROM reservation WHERE created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY) AND reservation_status IN ('PAID','CONFIRMED') GROUP BY content_id ) r ON r.content_id = c.content_id LEFT JOIN ( SELECT content_id, COUNT(*) AS like_cnt FROM content_like GROUP BY content_id ) l ON l.content_id = c.content_id WHERE
AND c.end_at >= NOW()
AND c.content_kind = #{kind}
ORDER BY (COALESCE(r.res_cnt,0)*3 + COALESCE(l.like_cnt,0)) DESC, c.start_at ASC LIMIT #{limit}

SELECT c.content_id AS content_id, c.title AS title, c.main_image_path AS main_image_path, c.category AS category, c.content_kind AS content_kind, c.location AS location, c.start_at AS start_at, c.end_at AS end_at FROM content c WHERE
AND c.start_at > NOW()
AND c.content_kind = #{kind}
ORDER BY c.start_at ASC LIMIT #{limit}

SELECT COUNT(*) FROM content c
AND c.end_at >= NOW()
AND ( c.title LIKE CONCAT('%', #{dto.q}, '%') OR c.description LIKE CONCAT('%', #{dto.q}, '%') OR c.location LIKE CONCAT('%', #{dto.q}, '%') )
AND c.content_kind = #{dto.content_kind}
AND c.category IN
#{cat}
AND c.place_tag IN
#{pt}
AND c.reservation_type = #{dto.reservation_type}
AND c.adult_price = 0
AND c.start_at >= STR_TO_DATE(CONCAT(#{dto.start_at}, ' 00:00:00'), '%Y-%m-%d %H:%i:%s')
AND c.end_at <= STR_TO_DATE(CONCAT(#{dto.end_at}, ' 23:59:59'), '%Y-%m-%d %H:%i:%s')

SELECT (SELECT COUNT(*) FROM content_like WHERE content_id = #{content_id}) AS like_count, c.title AS title, c.content_id AS content_id, c.start_at AS start_at, c.end_at AS end_at, c.location AS location, c.description AS description, c.adult_price AS adult_price, c.teen_price AS teen_price, c.child_price AS child_price, c.main_image_path AS main_image_path, c.detail_description as detail_description, c.reservation_type AS reservation_type, c.category AS category, c.content_time AS content_time, c.content_kind AS content_kind, c.x_url AS x_url, c.instagram_url AS instagram_url
FROM content c WHERE
AND c.content_id = #{content_id}

SELECT time_zone, current_ticket, schedule_id
FROM content_schedule
WHERE content_id=#{content_id}
AND scheduled_at= #{scheduled_at}
ORDER BY time_zone

SELECT user_id
FROM content
WHERE content_id=#{content_id}
